export interface BaseEvent {
  eventId: string;
  eventType: string;
  timestamp: string; // ISO 8601
  version: string;
  source: string; // emitting service name
  correlationId?: string;
}

// --- Order Events ---

export interface OrderCreatedEvent extends BaseEvent {
  eventType: 'order.created';
  payload: {
    orderId: string;
    userId: string;
    items: Array<{
      productId: string;
      sku: string;
      quantity: number;
      unitPrice: number;
    }>;
    totalAmount: number;
    currency: string;
  };
}

export interface OrderStatusChangedEvent extends BaseEvent {
  eventType: 'order.status_changed';
  payload: {
    orderId: string;
    userId: string;
    previousStatus: OrderStatus;
    newStatus: OrderStatus;
    reason?: string;
  };
}

export interface OrderCancelledEvent extends BaseEvent {
  eventType: 'order.cancelled';
  payload: {
    orderId: string;
    userId: string;
    reason: string;
    refundAmount: number;
  };
}

export type OrderStatus =
  | 'pending'
  | 'confirmed'
  | 'processing'
  | 'shipped'
  | 'delivered'
  | 'cancelled'
  | 'refunded';

// --- Product Events ---

export interface ProductCreatedEvent extends BaseEvent {
  eventType: 'product.created';
  payload: {
    productId: string;
    sku: string;
    name: string;
    price: number;
    currency: string;
    stockQuantity: number;
    categoryId: string;
  };
}

export interface ProductStockUpdatedEvent extends BaseEvent {
  eventType: 'product.stock_updated';
  payload: {
    productId: string;
    sku: string;
    previousQuantity: number;
    newQuantity: number;
    reason: 'purchase' | 'restock' | 'adjustment' | 'return';
  };
}

export interface ProductPriceChangedEvent extends BaseEvent {
  eventType: 'product.price_changed';
  payload: {
    productId: string;
    sku: string;
    previousPrice: number;
    newPrice: number;
    currency: string;
  };
}

// --- User Events ---

export interface UserRegisteredEvent extends BaseEvent {
  eventType: 'user.registered';
  payload: {
    userId: string;
    email: string;
    registeredAt: string;
  };
}

export interface UserProfileUpdatedEvent extends BaseEvent {
  eventType: 'user.profile_updated';
  payload: {
    userId: string;
    changedFields: string[];
  };
}

// --- Payment Events ---

export interface PaymentProcessedEvent extends BaseEvent {
  eventType: 'payment.processed';
  payload: {
    paymentId: string;
    orderId: string;
    userId: string;
    amount: number;
    currency: string;
    method: 'card' | 'wallet' | 'bank_transfer';
    status: 'success' | 'failed';
    failureReason?: string;
  };
}

export interface PaymentRefundedEvent extends BaseEvent {
  eventType: 'payment.refunded';
  payload: {
    paymentId: string;
    orderId: string;
    userId: string;
    refundAmount: number;
    currency: string;
  };
}

// --- Union type covering all events ---

export type DomainEvent =
  | OrderCreatedEvent
  | OrderStatusChangedEvent
  | OrderCancelledEvent
  | ProductCreatedEvent
  | ProductStockUpdatedEvent
  | ProductPriceChangedEvent
  | UserRegisteredEvent
  | UserProfileUpdatedEvent
  | PaymentProcessedEvent
  | PaymentRefundedEvent;

export type EventType = DomainEvent['eventType'];

